import os
import textwrap
from langchain_community.document_loaders import TextLoader
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain_community.embeddings import HuggingFaceEmbeddings
from langchain_community.vectorstores import FAISS
from langchain_community.llms import Ollama
from langchain_core.prompts import ChatPromptTemplate
from langchain.chains.combine_documents import create_stuff_documents_chain
from langchain.chains import create_retrieval_chain
from langchain_core.runnables import RunnablePassthrough
from langchain_core.output_parsers import StrOutputParser

# --- 1. Configuration and Setup ---

# Define paths and models
DOCS_DIR = "company_documents"
DOCUMENT_FILE = os.path.join(DOCS_DIR, "company_knowledge.txt")
VECTOR_DB_PATH = "faiss_index"
EMBEDDING_MODEL_NAME = "sentence-transformers/all-MiniLM-L6-v2"
LLM_MODEL_NAME = "llama2" # Ensure this model is pulled in Ollama (e.g., `ollama pull llama2`)
CHUNK_SIZE = 1000
CHUNK_OVERLAP = 200
TOP_K_RETRIEVAL = 4 # Number of relevant documents to retrieve

# Create a dummy document directory and file for demonstration
os.makedirs(DOCS_DIR, exist_ok=True)
