# --- 2. Document Loading and Splitting ---

def load_and_split_documents(file_path):
    """Loads a document and splits it into chunks."""
    print(f"Loading document from {file_path}...")
    loader = TextLoader(file_path)
    documents = loader.load()

    print(f"Splitting document into chunks (size: {CHUNK_SIZE}, overlap: {CHUNK_OVERLAP})...")
    text_splitter = RecursiveCharacterTextSplitter(
        chunk_size=CHUNK_SIZE,
        chunk_overlap=CHUNK_OVERLAP,
        length_function=len,
        add_start_index=True,
    )
    chunks = text_splitter.split_documents(documents)
    print(f"Created {len(chunks)} chunks.")
    return chunks

# --- 3. Embedding and Vector Database Creation ---

def create_vector_store(chunks, db_path, embedding_model_name):
    """Creates a FAISS vector store from document chunks and saves it."""
    print(f"Loading embedding model: {embedding_model_name}...")
    # Using 'cpu' for a safer default, remove if you have GPU setup and proper CUDA/cuDNN
    embeddings = HuggingFaceEmbeddings(model_name=embedding_model_name, model_kwargs={'device': 'cpu'})

    print("Creating FAISS vector store...")
    vector_store = FAISS.from_documents(chunks, embeddings)
    vector_store.save_local(db_path)
    print(f"Vector store created and saved to {db_path}.")
    return vector_store, embeddings

def load_vector_store(db_path, embeddings):
    """Loads an existing FAISS vector store."""
    print(f"Loading FAISS vector store from {db_path}...")
    vector_store = FAISS.load_local(db_path, embeddings, allow_dangerous_deserialization=True)
    print("Vector store loaded.")
    return vector_store

# --- 4. LLM and RAG Chain Setup ---

def setup_rag_chain(vector_store, llm_model_name, top_k_retrieval):
    """Sets up the Retrieval Augmented Generation chain."""
    print(f"Initializing LLM: {llm_model_name}...")
    llm = Ollama(model=llm_model_name, temperature=0) # temperature=0 for more factual responses

    # Define the prompt template
    prompt_template = ChatPromptTemplate.from_template(
        """You are an AI assistant for our internal company knowledge base.
        Use the following retrieved context to answer the question.
        If you don't know the answer based on the provided context, just say that you don't know, don't try to make up an answer.
        Ensure your answer is concise and directly addresses the user's question.

        Retrieved Context:
        {context}

        Question: {question}

        Answer:"""
    )

    # Create a retriever from the vector store
    retriever = vector_store.as_retriever(search_kwargs={"k": top_k_retrieval})
    print(f"Retriever configured to fetch top {top_k_retrieval} documents.")

    # Create a chain that combines documents into a single string for the LLM
    document_chain = create_stuff_documents_chain(llm, prompt_template)

    # Create the full retrieval chain
    rag_chain = create_retrieval_chain(retriever, document_chain)
    print("RAG chain setup complete.")
    return rag_chain

# --- 5. Main Execution Flow ---

def main():
    # 1. Ingest documents and create/load vector store
    if not os.path.exists(VECTOR_DB_PATH):
        document_chunks = load_and_split_documents(DOCUMENT_FILE)
        vector_store, embeddings = create_vector_store(document_chunks, VECTOR_DB_PATH, EMBEDDING_MODEL_NAME)
    else:
        # Load embedding model first
        embeddings = HuggingFaceEmbeddings(model_name=EMBEDDING_MODEL_NAME, model_kwargs={'device': 'cpu'})
        vector_store = load_vector_store(VECTOR_DB_PATH, embeddings)

    # 2. Setup RAG chain
    rag_chain = setup_rag_chain(vector_store, LLM_MODEL_NAME, TOP_K_RETRIEVAL)

    # 3. Interactive query loop
    print("\n--- Company Knowledge Base Chatbot ---")
    print("Type 'exit' to quit.")

    while True:
        query = input("\nYour query: ")
        if query.lower() == 'exit':
            break

        print("Searching and generating response...")
        try:
            # Invoke the RAG chain
            response = rag_chain.invoke({"input": query})

            # Print the LLM's answer
            print("\n--- Generated Answer ---")
            print(response["answer"])

            # Print the retrieved documents
            print("\n--- Retrieved Context Documents ---")
            for i, doc in enumerate(response["context"]):
                print(f"Document {i+1} (Source: {doc.metadata.get('source', 'N/A')}, Start Index: {doc.metadata.get('start_index', 'N/A')}):")
                print(textwrap.indent(doc.page_content, "    ") + "\n")

        except Exception as e:
            print(f"An error occurred: {e}")
            print("Please ensure Ollama is running and the model '{LLM_MODEL_NAME}' is pulled.")
            print("You can try `ollama run {LLM_MODEL_NAME}` in your terminal to check.")

if __name__ == "__main__":
    main()